function fillQuestionBanks(){
  let subjects=['I','She','He','They','We','My friend','The student','Our teacher','The researchers','The team'];
  let verbs=['work','talk','walk','help','learn','play','visit','clean','cook','open'];
  for(let n=0;tests.english.questions.length<200;n++){let s=subjects[n%subjects.length],v=verbs[n%verbs.length],time=n%3;if(time===0)tests.english.questions.push([`Choose the correct form: ${s} ___ English every day.`,[v,`${v}s`,`${v}ing`,`${v}ed`],s==='I'||s==='They'||s==='We'?0:1]);else if(time===1)tests.english.questions.push([`Complete: ${s} ___ ${v}ing when the lesson started.`,['was', 'were','is','has'],s==='I'||s==='He'||s==='She'||s==='My friend'||s==='Our teacher'||s==='The student'||s==='The team'?0:1]);else tests.english.questions.push([`Complete: ${s} ___ already ${v}ed the assignment.`,['have','has','had','are'],s==='I'||s==='They'||s==='We'||s==='The researchers'?0:1])}
  for(let n=0;tests.readiness.questions.length<200;n++){let a=2+n,b=3+(n%7),c=a+b,d=c+b;tests.readiness.questions.push([`Продолжите числовой ряд: ${a}, ${c}, ${d}, …`,[String(d+b),String(d+a),String(c+b+1),String(d+2*b)],0])}
  let langs=['Python','C++','Java'],structures=['стек','очередь','массив','список'],threats=['фишинг','DDoS-атака','троян','кейлоггер'],security=['конфиденциальность','целостность','доступность','аутентификация'];
  for(let n=0;tests.profile.questions.length<200;n++){if(n%2===0){let lang=langs[n%langs.length],item=structures[n%structures.length];tests.profile.questions.push([`Какое утверждение о структуре «${item}» верно при программировании на ${lang}?`,item==='стек'?['Элементы извлекаются последними добавленными','Элементы извлекаются первыми добавленными','Структура хранит только строки','Структура не содержит данных']:item==='очередь'?['Элементы извлекаются первыми добавленными','Элементы извлекаются последними добавленными','Она не поддерживает добавление','Она всегда отсортирована']:['Она хранит набор элементов','Она служит только для шифрования','Она удаляет программу','Она не имеет размера'],0])}else{let threat=threats[n%threats.length],goal=security[n%security.length];tests.profile.questions.push([`Какой термин ИБ связан с понятием «${threat}»?`,[threat,goal,'Компилятор','Сортировка'],0])}}
}
