function sectionName(){if(active.id==='english')return 'Лексико-грамматический тест';if(active.id==='readiness')return step<15?'Критическое мышление':'Аналитическое мышление';return step<20?'Алгоритмические языки программирования':'Основы информационной безопасности'}
const modal=document.querySelector('#test-modal'), app=document.querySelector('#test-app');let active,step,answers;
document.querySelectorAll('[data-test]').forEach(b=>b.addEventListener('click',()=>start(b.dataset.test,b.dataset.mode==='learn')));document.querySelector('.modal-close').onclick=close;modal.onclick=e=>{if(e.target===modal)close()};
function close(){modal.classList.remove('open');modal.setAttribute('aria-hidden','true')}function shuffle(list){return [...list].sort(()=>Math.random()-.5)}function start(id,learn=false){let limit=id==='english'?50:id==='readiness'?30:40;active={...tests[id],id,questions:shuffle(tests[id].questions).slice(0,limit),learn};step=0;answers=[];modal.classList.add('open');modal.setAttribute('aria-hidden','false');render()}
function render(){let q=active.questions[step],chosen=answers[step],review=active.learn&&chosen!==undefined;app.innerHTML=`<div class="quiz-top"><div><p class="eyebrow">${sectionName()}${active.learn?' · РЕЖИМ ТРЕНИРОВКИ':''}</p><h2>${active.title}</h2></div><span class="quiz-counter">${step+1} / ${active.questions.length}</span></div><div class="progress"><i style="width:${(step+1)/active.questions.length*100}%"></i></div><div class="question">${step+1}. ${q[0]}</div><div class="answers">${q[1].map((a,i)=>`<button class="answer ${chosen===i?'selected':''} ${review&&i===q[2]?'correct':''} ${review&&chosen===i&&i!==q[2]?'incorrect':''}" data-a="${i}">${String.fromCharCode(65+i)}. ${a}</button>`).join('')}</div>${review?`<p class="answer-feedback">${chosen===q[2]?'Верно!':'Правильный ответ: '+String.fromCharCode(65+q[2])+'. '+q[1][q[2]]}</p>`:''}<div class="quiz-actions"><button id="prev" ${step?'':'disabled'}>← Назад</button><button id="next" ${chosen===undefined?'disabled':''}>${step===active.questions.length-1?'Завершить':'Далее →'}</button></div>`;app.querySelectorAll('[data-a]').forEach(b=>b.onclick=()=>{if(!review){answers[step]=+b.dataset.a;render()}});app.querySelector('#prev').onclick=()=>{step--;render()};app.querySelector('#next').onclick=()=>{if(step<active.questions.length-1){step++;render()}else result()}}
function result(){const score=answers.reduce((s,a,i)=>s+(a===active.questions[i][2]),0),pct=Math.round(score/active.questions.length*100),message=pct>=80?'Отличный результат — вы уверенно владеете материалом.':pct>=50?'Хорошая основа. Повторите темы, где возникли сложности.':'Продолжайте подготовку: библиотека материалов уже ждёт вас.';app.innerHTML=`<div class="result"><p class="eyebrow">РЕЗУЛЬТАТ ГОТОВ</p><div class="score">${score}/${active.questions.length}</div><h2>${pct}% правильных ответов</h2><p>${message}</p><button onclick="start('${active.id}',${active.learn})">Пройти ещё раз</button></div>`}

var timerHandle=null,timeLeft=0;
function testSeconds(id){return id==='english'?3300:id==='readiness'?2100:2700}
function topicOf(q){if(q[3])return q[3];let text=String(q[0]).toLowerCase();if(active.id==='english')return 'Грамматика и лексика';if(active.id==='readiness')return /\d/.test(text)?'Аналитическое мышление':'Критическое мышление';return /шифр|уязв|атак|фиш|троян|кцд|доступ|парол|иб|tls|ddos|безопас/.test(text)?'Информационная безопасность':'Программирование'}
function explanation(q){if(q[4])return q[4];let topic=topicOf(q);if(topic==='Грамматика и лексика')return 'Проверьте форму глагола, время и согласование с подлежащим.';if(topic==='Аналитическое мышление')return 'Найдите правило изменения чисел и примените его к следующему элементу.';if(topic==='Критическое мышление')return 'Опирайтесь только на факты и логически следующие выводы.';if(topic==='Информационная безопасность')return 'Соотнесите угрозу или принцип защиты с его точным определением.';return 'Определите назначение конструкции, структуры данных или оператора.'}
function persist(){try{if(active)localStorage.setItem('magisterium-attempt',JSON.stringify({active,step,answers,timeLeft}))}catch(e){}}
function clearPersist(){try{localStorage.removeItem('magisterium-attempt')}catch(e){}}
function startTimer(){clearInterval(timerHandle);timerHandle=setInterval(()=>{timeLeft--;persist();let t=document.querySelector('#timer');if(t)t.textContent=`⏱ ${Math.floor(timeLeft/60)}:${String(timeLeft%60).padStart(2,'0')}`;if(timeLeft<=0){clearInterval(timerHandle);result()}},1000)}
function close(){clearInterval(timerHandle);persist();modal.classList.remove('open');modal.setAttribute('aria-hidden','true')}
function shuffle(list){return [...list].sort(()=>Math.random()-.5)}
function start(id,learn=false,questions=null){let saved;try{saved=JSON.parse(localStorage.getItem('magisterium-attempt'))}catch(e){}if(!questions&&saved&&saved.active&&saved.active.id===id&&confirm('Продолжить сохранённую попытку?')){active=saved.active;step=saved.step;answers=saved.answers;timeLeft=saved.timeLeft}else{let limit=id==='english'?50:id==='readiness'?30:40,qualityLimit={english:90,readiness:60,profile:70},bank=tests[id].questions.slice(0,qualityLimit[id]);active={...tests[id],id,questions:questions||shuffle(bank).slice(0,limit),learn};step=0;answers=[];timeLeft=testSeconds(id);persist()}modal.classList.add('open');modal.setAttribute('aria-hidden','false');startTimer();render()}
function render(){let q=active.questions[step],chosen=answers[step],review=active.learn&&chosen!==undefined;app.innerHTML=`<div class="quiz-top"><div><p class="eyebrow">${topicOf(q)}${active.learn?' · ТРЕНИРОВКА':''}</p><h2>${active.title}</h2></div><span class="quiz-counter" id="timer">⏱ ${Math.floor(timeLeft/60)}:${String(timeLeft%60).padStart(2,'0')}</span></div><div class="progress"><i style="width:${(step+1)/active.questions.length*100}%"></i></div><div class="question">${step+1}. ${q[0]}</div><div class="answers">${q[1].map((a,i)=>`<button class="answer ${chosen===i?'selected':''} ${review&&i===q[2]?'correct':''} ${review&&chosen===i&&i!==q[2]?'incorrect':''}" data-a="${i}">${String.fromCharCode(65+i)}. ${a}</button>`).join('')}</div>${review?`<p class="answer-feedback">${chosen===q[2]?'Верно!':'Правильный ответ: '+String.fromCharCode(65+q[2])+'. '+q[1][q[2]]}<br><small>${explanation(q)}</small></p>`:''}<div class="quiz-actions"><button id="prev" ${step?'':'disabled'}>← Назад</button><button id="next" ${chosen===undefined?'disabled':''}>${step===active.questions.length-1?'Завершить':'Далее →'}</button></div>`;app.querySelectorAll('[data-a]').forEach(b=>b.onclick=()=>{if(!review){answers[step]=+b.dataset.a;persist();render()}});app.querySelector('#prev').onclick=()=>{step--;persist();render()};app.querySelector('#next').onclick=()=>{if(step<active.questions.length-1){step++;persist();render()}else result()}}
function repeatMistakes(){let wrong=active.questions.filter((q,i)=>answers[i]!==q[2]);if(!wrong.length){alert('Ошибок нет — отличная работа!');return}clearPersist();start(active.id,true,wrong)}
function result(){clearInterval(timerHandle);clearPersist();let score=answers.reduce((s,a,i)=>s+(a===active.questions[i][2]),0),pct=Math.round(score/active.questions.length*100),stats={};active.questions.forEach((q,i)=>{let t=topicOf(q);stats[t]??={ok:0,total:0};stats[t].total++;if(answers[i]===q[2])stats[t].ok++});let rows=Object.entries(stats).map(([t,v])=>`<li><span>${t}</span><b>${v.ok}/${v.total}</b></li>`).join('');let errors=active.questions.map((q,i)=>answers[i]===q[2]?'':`<li>${i+1}. ${q[0]} <b>→ ${q[1][q[2]]}</b></li>`).filter(Boolean).join('')||'<li>Нет ошибок.</li>';app.innerHTML=`<div class="result"><p class="eyebrow">РЕЗУЛЬТАТ ГОТОВ</p><div class="score">${score}/${active.questions.length}</div><h2>${pct}% правильных ответов</h2><div class="result-breakdown"><b>Результаты по темам</b><ul>${rows}</ul></div><details class="mistakes"><summary>Посмотреть ошибки (${active.questions.length-score})</summary><ol>${errors}</ol></details><button onclick="repeatMistakes()">Повторить ошибки</button><button onclick="start('${active.id}',${active.learn})">Новая попытка</button></div>`}
